begin;

create table if not exists public.conversion_feature_snapshots(
  id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,lead_id uuid not null references public.leads(id) on delete cascade,
  feature_cutoff_at timestamptz not null,horizon_days integer not null default 90 check(horizon_days in(30,60,90,180)),feature_schema_version integer not null default 1,
  features jsonb not null,predicted_probability numeric(5,2) not null check(predicted_probability between 0 and 100),model_version text not null,input_hash text not null,
  created_by uuid not null references public.profiles(id),created_at timestamptz not null default now(),unique(organization_id,lead_id,feature_cutoff_at,model_version)
);
create table if not exists public.conversion_outcome_labels(
  id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,lead_id uuid not null references public.leads(id) on delete cascade,
  outcome text not null check(outcome in('won','lost','external_purchase')),label_value smallint not null check(label_value in(0,1)),outcome_at timestamptz not null,
  source_event_id uuid references public.lead_behavior_events(id) on delete restrict,label_key text not null,label_schema_version integer not null default 1,created_at timestamptz not null default now(),unique(organization_id,source_event_id),unique(organization_id,label_key)
);
create table if not exists public.conversion_dataset_versions(
  id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,version integer not null,cutoff_at timestamptz not null,horizon_days integer not null,
  feature_schema_version integer not null,label_schema_version integer not null,example_count integer not null,positive_count integer not null,negative_count integer not null,
  status text not null default 'draft' check(status in('draft','validated','archived')),minimum_sample integer not null default 100,created_by uuid not null references public.profiles(id),created_at timestamptz not null default now(),unique(organization_id,version)
);
create index if not exists conversion_feature_snapshot_timeline_idx on public.conversion_feature_snapshots(organization_id,lead_id,feature_cutoff_at desc);
create index if not exists conversion_outcome_label_timeline_idx on public.conversion_outcome_labels(organization_id,lead_id,outcome_at);
alter table public.conversion_feature_snapshots enable row level security;alter table public.conversion_outcome_labels enable row level security;alter table public.conversion_dataset_versions enable row level security;
drop policy if exists conversion_feature_snapshots_scope on public.conversion_feature_snapshots;create policy conversion_feature_snapshots_scope on public.conversion_feature_snapshots for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));
drop policy if exists conversion_outcome_labels_scope on public.conversion_outcome_labels;create policy conversion_outcome_labels_scope on public.conversion_outcome_labels for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));
drop policy if exists conversion_dataset_versions_scope on public.conversion_dataset_versions;create policy conversion_dataset_versions_scope on public.conversion_dataset_versions for select to authenticated using(organization_id=(select public.current_organization_id()));
revoke all on public.conversion_feature_snapshots,public.conversion_outcome_labels,public.conversion_dataset_versions from anon;revoke insert,update,delete on public.conversion_feature_snapshots,public.conversion_outcome_labels,public.conversion_dataset_versions from authenticated;grant select on public.conversion_feature_snapshots,public.conversion_outcome_labels,public.conversion_dataset_versions to authenticated;grant all on public.conversion_feature_snapshots,public.conversion_outcome_labels,public.conversion_dataset_versions to service_role;

create or replace function private.capture_conversion_outcome_label()returns trigger language plpgsql security definer set search_path='' as $$declare normalized_outcome text;begin if new.event_name not in('conversion_won','conversion_lost','external_purchase')then return new;end if;normalized_outcome:=case new.event_name when'conversion_won'then'won'when'conversion_lost'then'lost'else'external_purchase'end;insert into public.conversion_outcome_labels(organization_id,lead_id,outcome,label_value,outcome_at,source_event_id,label_key)values(new.organization_id,new.lead_id,normalized_outcome,case when normalized_outcome='won'then 1 else 0 end,new.occurred_at,new.id,'behavior-event:'||new.id::text)on conflict(organization_id,label_key)do nothing;return new;end $$;
drop trigger if exists capture_conversion_outcome_label_insert on public.lead_behavior_events;create trigger capture_conversion_outcome_label_insert after insert on public.lead_behavior_events for each row when(new.event_name in('conversion_won','conversion_lost','external_purchase'))execute function private.capture_conversion_outcome_label();

insert into public.conversion_outcome_labels(organization_id,lead_id,outcome,label_value,outcome_at,source_event_id,label_key)
select e.organization_id,e.lead_id,case e.event_name when'conversion_won'then'won'when'conversion_lost'then'lost'else'external_purchase'end,case when e.event_name='conversion_won'then 1 else 0 end,e.occurred_at,e.id,'behavior-event:'||e.id::text from public.lead_behavior_events e where e.event_name in('conversion_won','conversion_lost','external_purchase')on conflict(organization_id,label_key)do nothing;
insert into public.conversion_outcome_labels(organization_id,lead_id,outcome,label_value,outcome_at,label_key)
select x.organization_id,x.lead_id,case x.to_stage when'ganho'then'won'when'perdido'then'lost'else'external_purchase'end,case when x.to_stage='ganho'then 1 else 0 end,x.occurred_at,'pipeline-move:'||x.id::text from(select distinct on(m.organization_id,m.lead_id)m.id,m.organization_id,m.lead_id,lower(m.to_stage)to_stage,m.occurred_at from public.pipeline_stage_moves m where lower(m.to_stage)in('ganho','perdido','comprou_outro')and not exists(select 1 from public.conversion_outcome_labels o where o.organization_id=m.organization_id and o.lead_id=m.lead_id)order by m.organization_id,m.lead_id,m.occurred_at)x on conflict(organization_id,label_key)do nothing;

create or replace function public.snapshot_conversion_cohort(p_actor_id uuid,p_organization_id uuid,p_horizon_days integer default 90)
returns jsonb language plpgsql security definer set search_path='' as $$declare actor_role text;cutoff timestamptz:=date_trunc('minute',now());inserted integer:=0;examples integer:=0;positives integer:=0;negatives integer:=0;dataset_version integer;dataset_id uuid;
begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;if actor_role not in('director','superintendent')then raise exception 'conversion_dataset_actor_forbidden';end if;if p_horizon_days not in(30,60,90,180)then raise exception 'conversion_dataset_horizon_invalid';end if;
  insert into public.conversion_feature_snapshots(organization_id,lead_id,feature_cutoff_at,horizon_days,features,predicted_probability,model_version,input_hash,created_by)
  select l.organization_id,l.id,cutoff,p_horizon_days,jsonb_build_object('stage',lower(coalesce(l.status,'novo')),'score',greatest(0,least(100,coalesce(l.score,0))),'dataQualityPercent',greatest(0,least(100,coalesce(l.data_quality_percent,0))),'engagementCount',coalesce(ev.engagement,0),'visitCount',coalesce(ev.visits,0),'proposalCount',coalesce(ev.proposals,0),'positiveSignalCount',coalesce(ev.positive,0),'negativeSignalCount',coalesce(ev.negative,0),'leadAgeDays',greatest(0,floor(extract(epoch from(cutoff-l.created_at))/86400)::integer)),greatest(1,least(95,10+coalesce(l.score,0)*.55+case lower(coalesce(l.status,'novo'))when'contato'then 4 when'qualificacao'then 12 when'visita'then 20 when'proposta'then 30 when'contrato'then 42 else 0 end)), 'atlas-baseline-v1',encode(digest(concat_ws('|',l.id::text,cutoff::text,coalesce(l.status,''),coalesce(l.score,0)::text,coalesce(ev.total,0)::text),'sha256'),'hex'),p_actor_id
  from public.leads l left join lateral(select count(*) total,count(*)filter(where event_category='engagement')engagement,count(*)filter(where event_category='visit')visits,count(*)filter(where event_category='proposal')proposals,count(*)filter(where direction='positive')positive,count(*)filter(where direction='negative')negative from public.lead_behavior_events e where e.organization_id=l.organization_id and e.lead_id=l.id and e.occurred_at<=cutoff)ev on true
  where l.organization_id=p_organization_id and lower(coalesce(l.status,'novo'))not in('ganho','won','vendido','perdido','lost','comprou_outro','arquivado','archived','descartado','discarded')and not exists(select 1 from public.conversion_outcome_labels o where o.organization_id=l.organization_id and o.lead_id=l.id and o.outcome_at<=cutoff)
  on conflict(organization_id,lead_id,feature_cutoff_at,model_version)do nothing;get diagnostics inserted=row_count;
  select count(*),count(*)filter(where o.label_value=1),count(*)filter(where o.label_value=0)into examples,positives,negatives from public.conversion_feature_snapshots s join lateral(select label_value,outcome_at from public.conversion_outcome_labels x where x.organization_id=s.organization_id and x.lead_id=s.lead_id and x.outcome_at>s.feature_cutoff_at and x.outcome_at<=s.feature_cutoff_at+make_interval(days=>s.horizon_days)order by x.outcome_at limit 1)o on true where s.organization_id=p_organization_id;
  perform pg_advisory_xact_lock(hashtextextended('conversion-dataset:'||p_organization_id::text,0));select coalesce(max(version),0)+1 into dataset_version from public.conversion_dataset_versions where organization_id=p_organization_id;
  insert into public.conversion_dataset_versions(organization_id,version,cutoff_at,horizon_days,feature_schema_version,label_schema_version,example_count,positive_count,negative_count,status,created_by)values(p_organization_id,dataset_version,cutoff,p_horizon_days,1,1,examples,positives,negatives,case when examples>=100 and positives>=20 and negatives>=20 then'validated'else'draft'end,p_actor_id)returning id into dataset_id;
  return jsonb_build_object('datasetId',dataset_id,'version',dataset_version,'snapshotsCreated',inserted,'examples',examples,'positive',positives,'negative',negatives,'sampleSufficient',examples>=100 and positives>=20 and negatives>=20,'futureLeakagePrevented',true,'personalDataIncluded',false);
end $$;
revoke all on function public.snapshot_conversion_cohort(uuid,uuid,integer)from public,anon,authenticated;grant execute on function public.snapshot_conversion_cohort(uuid,uuid,integer)to service_role;
commit;
